
const RITUAL_KEY='Vathkül';
let participantName='';
let stateChangeHandler=()=>{};
let isApplyingRemoteState=false;
let ritualJournal=[];
let purificationMode=false;
let purificationTargetIndex=null;
let purificationDC=20;
let ritualDestroyed=false;
let finalSequenceRunning=false;
let lokaugSwapMode=false;
let lokaugFirstSwapIndex=null;

function normalizeRitualKey(value){
  return value.trim().normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase();
}
function openEntryGate(){
  const gate=document.getElementById('entryGate');
  gate.classList.remove('opening');
  gate.style.display='flex';
  const saved=localStorage.getItem('projectMonolithCharacter')||'';
  document.getElementById('characterName').value=saved;
  setTimeout(()=>document.getElementById('characterName').focus(),80);
}
function enterRitual(name){
  participantName=name.trim();
  localStorage.setItem('projectMonolithCharacter',participantName);
  document.getElementById('participantChip').textContent=participantName;
  const gate=document.getElementById('entryGate');
  gate.classList.add('opening');
  setTimeout(()=>gate.style.display='none',560);
  window.dispatchEvent(new CustomEvent('project-monolith:entered',{
    detail:{participantName,ritualKey:RITUAL_KEY}
  }));
}
function initializeEntryGate(){
  const form=document.getElementById('entryForm');
  const error=document.getElementById('entryError');
  form.addEventListener('submit',event=>{
    event.preventDefault();
    const name=document.getElementById('characterName').value.trim();
    const key=document.getElementById('ritualKey').value;
    if(!name){error.textContent='Inscrivez le nom de votre personnage.';return;}
    if(normalizeRitualKey(key)!==normalizeRitualKey(RITUAL_KEY)){
      error.textContent='La pierre demeure silencieuse. Cette clé n’est pas reconnue.';
      return;
    }
    error.textContent='';
    enterRitual(name);
  });
  document.getElementById('participantChip').addEventListener('click',openEntryGate);
  openEntryGate();
}

const GLYPHS={"abjuration": "data:image/png;base64,", "divination": "data:image/png;base64,", "conjuration": "data:image/png;base64,", "enchantment": "data:image/png;base64,", "evocation": "data:image/png;base64,", "illusion": "data:image/png;base64,", "necromancy": "data:image/png;base64,", "transmutation": "data:image/png;base64,"};

const schools=['abjuration','divination','conjuration','enchantment','evocation','illusion','necromancy','transmutation'];
const solution=['divination','abjuration','enchantment','necromancy','transmutation','evocation','conjuration','illusion'];
const abyss=solution.map((_,i)=>solution[(i+4)%8]);
const pos=[[50,14.5],[75.1,24.9],[85.5,50],[75.1,75.1],[50,85.5],[24.9,75.1],[14.5,50],[24.9,24.9]];

const stationNames=['Œil','Tour','Chaîne','Crâne','Spirale','Flamme','Porte','Voile'];
