let placements=Array(8).fill(null);
let order=[...schools];
let selected=null;
let life=15;
let memoryLevel=Array(8).fill(0);
let corrupted=new Set();
let lastGM=null;
let finalReady=false;
let pendingPurification=null;
let purificationBoosted=false;
let evaluationVisible=false;
let ritualCompleted=false;
let lastRenderedPlacements=Array(8).fill(null);
let hasCompletedInitialRender=false;

function invalidateEvaluation(){
  evaluationVisible=false;
  finalReady=false;
  document.getElementById('core').classList.remove('ready');
  document.getElementById('score').textContent='?';
  document.getElementById('links').innerHTML='';
}

function build(){
  const board=document.getElementById('board');

  if(!board.querySelector('.rune-layer')){
    const runeLayer=document.createElement('div');
    runeLayer.className='rune-layer';
    const runeAlphabet=['ᚠ','ᚢ','ᚦ','ᚨ','ᚱ','ᚲ','ᚷ','ᚹ','ᚺ','ᚾ','ᛁ','ᛃ','ᛇ','ᛈ','ᛉ','ᛊ','ᛏ','ᛒ','ᛖ','ᛗ','ᛚ','ᛜ','ᛞ','ᛟ'];

    [38.5,46].forEach((radius,ringIndex)=>{
      const count=ringIndex===0?24:32;
      for(let i=0;i<count;i++){
        const rune=document.createElement('span');
        const angle=(360/count)*i+(ringIndex?5:0);
        const radians=(angle-90)*Math.PI/180;
        const x=50+Math.cos(radians)*radius;
        const y=50+Math.sin(radians)*radius;

        rune.className=`board-rune rune-ring-${ringIndex+1}`;
        rune.textContent=runeAlphabet[(i+ringIndex*7)%runeAlphabet.length];
        rune.style.left=`${x}%`;
        rune.style.top=`${y}%`;
        rune.style.setProperty('--rune-rotation',`${angle}deg`);
        runeLayer.appendChild(rune);
      }
    });

    board.prepend(runeLayer);
  }

  for(let i=0;i<8;i++){
    const slot=document.createElement('div');
    slot.className='slot';
    slot.style.left=pos[i][0]+'%';slot.style.top=pos[i][1]+'%';
    slot.innerHTML=`<span class="station-sigil" title="${stationNames[i]}">${sigils[i]}</span>`;
    slot.ondragover=e=>{e.preventDefault();slot.classList.add('dragover')};
    slot.ondragleave=()=>slot.classList.remove('dragover');
    slot.ondrop=e=>drop(e,i);
    slot.onclick=()=>{
      if(lokaugSwapMode){
        chooseLokaugSwapTarget(i);
        return;
      }
      if(purificationMode){
        choosePurificationTarget(i);
        return;
      }
      selectSlot(i);
    };
    board.appendChild(slot);
  }
  render();
}

function selectSlot(i){
  selected=i;
  document.querySelectorAll('.slot').forEach((s,j)=>s.classList.toggle('selected',j===i));
  document.getElementById('memoryText').textContent=memoryLevel[i]
    ? memories[i][memoryLevel[i]-1]
    : `Aucun souvenir n’a encore été éveillé pour la gravure « ${stationNames[i]} ».`;
  say(`La gravure « ${stationNames[i]} » est sélectionnée.`);
}

function drop(e,i){
  e.preventDefault();
  document.querySelectorAll('.slot').forEach(s=>s.classList.remove('dragover'));
  const school=e.dataTransfer.getData('school');
  if(!school)return;
  const old=placements.indexOf(school);
  if(old>=0)placements[old]=null;
  placements[i]=school;
  invalidateEvaluation();
  render();
}

function render(){
  document.body.classList.toggle('ritual-destroyed',ritualDestroyed);
  setRitualLocked(ritualDestroyed);
  const changedSlots=[];
  placements.forEach((school,index)=>{
    if(hasCompletedInitialRender && school!==lastRenderedPlacements[index])changedSlots.push(index);
  });

  document.querySelectorAll('.slot').forEach((slot,i)=>{
    slot
slot.classList.toggle('corrupted',corrupted.has(i));
    slot.classList.toggle('glyph-changing',changedSlots.includes(i));
    slot.querySelectorAll('img').forEach(x=>x.remove());

    if(placements[i]){
      const img=document.createElement('img');
      img.className='placed';
      img.dataset.school=placements[i];
      img.src=GLYPHS[placements[i]];
      img.draggable=true;
      img.ondragstart=e=>{
        e.dataTransfer.effectAllowed='move';
        e.dataTransfer.setData('school',placements[i]);
        requestAnimationFrame(()=>img.classList.add('dragging'));
      };
      img.ondragend=()=>img.classList.remove('dragging');
      img.onclick=event=>{
        if(lokaugSwapMode){
          event.preventDefault();
          event.stopPropagation();
          chooseLokaugSwapTarget(i);
          return;
        }
        if(!purificationMode)return;
        event.preventDefault();
        event.stopPropagation();
        choosePurificationTarget(i);
      };
      img.ondblclick=()=>{
        placements[i]=null;
        invalidateEvaluation();
        render();
      };
      slot.appendChild(img);
    }

    if(changedSlots.includes(i)){
      setTimeout(()=>slot.classList.remove('glyph-changing'),520);
    }
  });

  const tray=document.getElementById('tiles');
  tray.innerHTML='';
  order.forEach(sc=>{
    const tile=document.createElement('div');
    tile.className='tile'+(placements.includes(sc)?' used':'');
    tile.dataset.school=sc;
    tile.draggable=!placements.includes(sc);
    tile.innerHTML=`<img src="${GLYPHS[sc]}" alt="glyphe">`;
    tile.ondragstart=e=>{
      e.dataTransfer.effectAllowed='move';
      e.dataTransfer.setData('school',sc);
      requestAnimationFrame(()=>tile.classList.add('dragging'));
    };
    tile.ondragend=()=>tile.classList.remove('dragging');
    tray.appendChild(tile);
  });

  lastRenderedPlacements=[...placements];
  hasCompletedInitialRender=true;
  update();
}

function score(){
  let good=0,aby=0;
  placements.forEach((s,i)=>{
    if(s===solution[i]&&!corrupted.has(i))good++;
    if(s===abyss[i])aby++;
  });
  return {good,aby};
}




let previousLife=15;
const spokenThresholds=new Set();
const thresholdLines={
  12:'« Ne retenez pas votre main… Ces Étincelles ne m’ont jamais été données pour être conservées, mais pour accomplir mon serment. »',
  9:'« Je sens… le poids des siècles revenir. Continuez. N’ayez aucun regret pour moi. »',
  6:'« La lumière de Torm vacille en moi… mais tant qu’une seule Étincelle brillera encore, je tiendrai cette garde. »',
  3:'« Écoutez-moi… après cela, je ne pourrai probablement plus vous guider. Faites confiance à votre jugement… pas au mien. »',
  1:'« Voici… la dernière. Torm… mon devoir touche à sa fin… »',
  0:'« Mon serment… vous appartient désormais… »'
};

function buildSparks(){
  const container=document.getElementById('sparks');
  if(!container || container.children.length===15)return;
  container.innerHTML='';
  for(let i=0;i<15;i++){
    const flame=document.createElement('span');
    flame.className='spark';
    flame.setAttribute('aria-hidden','true');
    container.appendChild(flame);
  }
}

function animateReturningSpark(){
  const board=document.getElementById('board');
  const particle=document.createElement('span');
  particle.className='spark-particle';
  board.appendChild(particle);
  setTimeout(()=>particle.remove(),1600);

  const notice=document.createElement('div');
  notice.className='spark-message';
  notice.textContent='Une Étincelle de Torm retourne à son créateur…';
  document.body.appendChild(notice);
  setTimeout(()=>notice.remove(),1900);
}

function speakThreshold(oldValue,newValue){
  [12,9,6,3,1,0].forEach(threshold=>{
    if(oldValue>threshold && newValue<=threshold && !spokenThresholds.has(threshold)){
      spokenThresholds.add(threshold);
      const line=thresholdLines[threshold];
      document.getElementById('vathkulVoice').textContent=line;
      say(`Vathkül : ${line}`);
    }
  });
}

function spendSparks(amount=1){
  if(amount<=0)return true;
  if(life<amount)return false;
  const old=life;
  life=Math.max(0,life-amount);
  for(let i=0;i<amount;i++)setTimeout(animateReturningSpark,i*180);
  speakThreshold(old,life);
  update();
  return true;
}

function renderSparks(){
  buildSparks();
  const flames=[...document.querySelectorAll('.spark')];
  flames.forEach((flame,i)=>flame.classList.toggle('spent',i>=life));

  if(life<previousLife){
    for(let lost=previousLife-1;lost>=life;lost--){
      const flame=flames[lost];
      if(flame){
        flame.classList.remove('spent');
        flame.classList.add('extinguishing');
        setTimeout(()=>{
          flame.classList.remove('extinguishing');
          flame.classList.add('spent');
        },700);
      }
    }
  }
  previousLife=life;
}

function update(){
  const {good,aby}=score();
  document.getElementById('life').textContent=life;
  renderSparks();
  document.getElementById('score').textContent=evaluationVisible?good:'?';
  document.getElementById('links').innerHTML='';

  if(evaluationVisible){
    for(let i=0;i<8;i++){
      const j=(i+1)%8;
      const stable=placements[i]===solution[i]&&placements[j]===solution[j]&&!corrupted.has(i)&&!corrupted.has(j);
      const dark=placements[i]===abyss[i]&&placements[j]===abyss[j];
      if(!stable&&!dark)continue;
      const path=document.createElementNS('http://www.w3.org/2000/svg','path');
      path.setAttribute('d',`M ${pos[i][0]} ${pos[i][1]} L ${pos[j][0]} ${pos[j][1]}`);
      path.setAttribute('class','link'+(dark?' abyss':''));
      path.setAttribute('pathLength','1');
      document.getElementById('links').appendChild(path);
    }
  }

  finalReady=evaluationVisible&&good===8;
  const core=document.getElementById('core');
  core.classList.toggle('ready',finalReady);
  core.classList.toggle('weakened',life<=9&&life>3);
  core.classList.toggle('failing',life<=3&&life>0);
  core.classList.toggle('extinguished',life===0);

  const memoryButton=document.getElementById('memory');
  const purifyButton=document.getElementById('beginPurify');
  if(memoryButton)memoryButton.disabled=life===0;
  if(purifyButton)purifyButton.disabled=life===0;
  if(!isApplyingRemoteState)stateChangeHandler();
}

function speakVathkul(line){
  const quoted=`« ${line} »`;
  document.getElementById('vathkulVoice').textContent=quoted;
  say(`Vathkül : ${quoted}`);
}


function chooseVathkulLine(lines){
  if(!Array.isArray(lines) || lines.length===0){
    return 'Le Monolithe demeure silencieux.';
  }
  return lines[Math.floor(Math.random()*lines.length)];
}


function startLokaugSwap(){
  lokaugSwapMode=true;
  lokaugFirstSwapIndex=null;

  document.querySelectorAll('.slot').forEach(slot=>{
    slot.classList.add('lokaug-swap-selectable');
    slot.classList.remove('lokaug-swap-first');
  });

  addJournalEntry('Lokaug prépare l’échange de deux glyphes.','Lokaug');
  speakVathkul('Choisissez le premier glyphe.');
  update();
}

function cancelLokaugSwap(){
  lokaugSwapMode=false;
  lokaugFirstSwapIndex=null;

  document.querySelectorAll('.slot').forEach(slot=>{
    slot.classList.remove('lokaug-swap-selectable','lokaug-swap-first');
  });
}

function chooseLokaugSwapTarget(index){
  if(!lokaugSwapMode)return false;

  if(!placements[index]){
    speakVathkul('Aucun glyphe ne repose à cet emplacement.');
    update();
    return true;
  }

  if(lokaugFirstSwapIndex===null){
    lokaugFirstSwapIndex=index;

    document.querySelectorAll('.slot').forEach((slot,slotIndex)=>{
      slot.classList.toggle('lokaug-swap-first',slotIndex===index);
    });

    addJournalEntry('Premier glyphe sélectionné pour l’échange.','Lokaug');
    speakVathkul('Choisissez le second glyphe.');
    update();
    return true;
  }

  if(index===lokaugFirstSwapIndex){
    speakVathkul('Choisissez un autre glyphe.');
    update();
    return true;
  }

  const firstIndex=lokaugFirstSwapIndex;
  [placements[firstIndex],placements[index]]=[placements[index],placements[firstIndex]];

  addJournalEntry('Lokaug échange deux glyphes.','Lokaug');
  speakVathkul('Deux glyphes ont échangé leur place.');

  cancelLokaugSwap();
  update();
  stateChangeHandler();
  return true;
}

function analyzeGlyphConfiguration(){
  const positionKeys=[
    'nord',
    'nordEst',
    'est',
    'sudEst',
    'sud',
    'sudOuest',
    'ouest',
    'nordOuest'
  ];

  const incorrect=[];
  const empty=[];
  const inversions=[];

  for(let i=0;i<placements.length;i++){
    const placed=placements[i];
    const expected=schools[i];

    if(!placed){
      empty.push(i);
      incorrect.push(i);
      continue;
    }

    if(placed!==expected){
      incorrect.push(i);
    }
  }

  for(let i=0;i<placements.length;i++){
    if(!placements[i] || placements[i]===schools[i])continue;

    for(let j=i+1;j<placements.length;j++){
      if(!placements[j] || placements[j]===schools[j])continue;

      if(placements[i]===schools[j] && placements[j]===schools[i]){
        inversions.push([i,j]);
      }
    }
  }

  return {
    correctCount:placements.length-incorrect.length,
    placedCount:placements.filter(Boolean).length,
    incorrect,
    empty,
    inversions,
    incorrectPositions:incorrect.map(index=>positionKeys[index])
  };
}

function inspectInnerEngravings(){
  const dialogues=window.VATHKUL_DIALOGUES?.inspect || {};
  const analysis=analyzeGlyphConfiguration();
  let line='Le Monolithe demeure silencieux.';

  if(analysis.placedCount===0){
    line=chooseVathkulLine(dialogues.empty);
  }else if(analysis.inversions.length>0){
    line=chooseVathkulLine(dialogues.inversion);
  }else if(analysis.incorrect.length===1){
    const positionKey=analysis.incorrectPositions[0];
    line=chooseVathkulLine(dialogues.position?.[positionKey]);
  }else if(analysis.correctCount<=3){
    line=chooseVathkulLine(dialogues.few);
  }else if(analysis.correctCount<=6){
    line=chooseVathkulLine(dialogues.middle);
  }else if(analysis.correctCount===7){
    line=chooseVathkulLine(dialogues.almost);
  }else{
    line=chooseVathkulLine(dialogues.perfect);
  }

  speakVathkul(line);
  update();
  document.getElementById('muralOverlay').classList.add('show');
}


function setRitualLocked(locked){
  document.body.classList.toggle('ritual-locked',locked);

  document.querySelectorAll(
    '.tile, .slot, #test, #openMural, #beginPurify, #lokaugSwap, .controls button'
  ).forEach(element=>{
    if('disabled' in element){
      element.disabled=locked;
    }
    element.setAttribute('aria-disabled',locked?'true':'false');
  });
}

function isPerfectConfiguration(){
  const everyPlaced=placements.every(Boolean);
  const everyCorrect=placements.every((school,index)=>school===schools[index]);
  const noCorruption=corrupted.size===0;

  return everyPlaced && everyCorrect && noCorruption;
}

function startFinalRitualSequence(){
  if(finalSequenceRunning || ritualDestroyed)return;

  finalSequenceRunning=true;
  ritualDestroyed=true;
  setRitualLocked(true);

  const boardWrap=document.querySelector('.board-wrap');
  const board=document.getElementById('board');
  const vathkulPanel=document.querySelector('.vathkul-dialogue');
  const vathkulPortrait=document.querySelector('.vathkul-portrait');
  const overlay=document.getElementById('finalRitualOverlay');

  boardWrap?.classList.add('final-awakening');
  board?.classList.add('final-awakening');
  vathkulPanel?.classList.add('vathkul-fading');
  vathkulPortrait?.classList.add('vathkul-fading');

  addJournalEntry('La fresque s’illumine.','Le Monolithe');
  update();

  window.setTimeout(()=>{
    overlay?.classList.add('show');
    overlay?.setAttribute('aria-hidden','false');
    boardWrap?.classList.add('final-flash');
  },1700);

  window.setTimeout(()=>{
    board?.classList.add('final-cracking');
    boardWrap?.classList.add('final-cracking');
    addJournalEntry('Le Monolithe se fissure.','Le Monolithe');
    update();
  },2450);

  window.setTimeout(()=>{
    board?.classList.add('final-destruction');
    boardWrap?.classList.add('final-destruction');
    document.body.classList.add('vathkul-gone');

    if(typeof vathkulText!=='undefined'){
      vathkulText='';
    }

    addJournalEntry('La présence de Vathkül s’est éteinte.','Le Monolithe');
    update();
  },3900);

  window.setTimeout(()=>{
    overlay?.classList.add('message-visible');
    finalSequenceRunning=false;
    update();
  },5000);
}


function testConfiguration(){
  if(ritualDestroyed || finalSequenceRunning)return;

  const {good}=score();
  const placedCount=placements.filter(Boolean).length;

  if(placedCount===0){
    speakVathkul('Le Monolithe demeure silencieux.');
    update();
    return;
  }

  if(isPerfectConfiguration()){
    startFinalRitualSequence();
    return;
  }

  if(good===8 && corrupted.size>0){
    speakVathkul('L’équilibre demeure impossible tant qu’un glyphe reste corrompu.');
    addJournalEntry('La corruption empêche l’accomplissement du rituel.','Le Monolithe');
    document.querySelector('.board-wrap')?.classList.add('configuration-corrupted');
    window.setTimeout(
      ()=>document.querySelector('.board-wrap')?.classList.remove('configuration-corrupted'),
      900
    );
    update();
    return;
  }

  if(good===7){
    speakVathkul('Une résonance s’établit… mais elle demeure incomplète.');
    document.querySelector('.board-wrap')?.classList.add('configuration-close');
    window.setTimeout(
      ()=>document.querySelector('.board-wrap')?.classList.remove('configuration-close'),
      1000
    );
    update();
    return;
  }

  if(placedCount<8){
    speakVathkul('La configuration est trop incomplète pour être éprouvée.');
    update();
    return;
  }

  speakVathkul('L’équilibre se refuse à vous.');
  document.querySelector('.board-wrap')?.classList.add('configuration-failed');
  window.setTimeout(
    ()=>document.querySelector('.board-wrap')?.classList.remove('configuration-failed'),
    700
  );
  update();
}

function awakenMemory(){
  if(selected===null){say('Sélectionnez d’abord une gravure.');return;}
  if(memoryLevel[selected]>=2){say('Vathkül ne possède plus aucun autre souvenir concernant cette gravure.');return;}
  if(!spendSparks(1)){say('Aucune Étincelle ne subsiste pour raviver un nouveau souvenir.');return;}
  const text=memories[selected][memoryLevel[selected]];
  memoryLevel[selected]++;
  document.getElementById('memoryText').textContent=text;
  document.getElementById('memoryStage').textContent=
    'Vathkül ferme les yeux. Une lumière pâle traverse les fissures du Monolithe.\n\n« '+text+' »';
  document.getElementById('memoryOverlay').classList.add('show');
  update();
}

function release(){
  if(ritualCompleted)return;
  if(!finalReady){
    say('Le calcul n’est pas encore entièrement accordé.');
    return;
  }
  ritualCompleted=true;
  document.getElementById('phase').innerHTML='<b>Dissolution :</b> Vathkül libère le Sang de la Terre. Le calcul devient irréversible.';
  say('Les huit fonctions s’embrasent. Le Monolithe commence à se replier sur sa propre architecture planaire.');
  document.getElementById('board').classList.add('dissolving');
  document.querySelectorAll('button').forEach(b=>b.disabled=true);
  setTimeout(()=>document.getElementById('victory').classList.add('show'),2600);
}

function beginPurification(){
  if(selected===null){
    say('Sélectionnez d’abord une gravure parasitée.');
    return;
  }
  if(!corrupted.has(selected)){
    speakVathkul('Cette gravure est déjà pure.');
    return;
  }
  if(!spendSparks(1)){
    say('Aucune Étincelle ne subsiste pour soutenir une purification.');
    return;
  }
  pendingPurification=selected;
  purificationBoosted=false;

  document.getElementById('purifyPrompt').textContent=
    `Vathkül engage déjà 1 Étincelle de Torm pour retenir le parasitage de la gravure « ${stationNames[selected]} ».`;
  document.getElementById('purifyResult').textContent=
    'Choisissez : tenter un test DD 20, ou demander à Vathkül de dépenser 1 Étincelle supplémentaire pour réduire le DD à 15.';
  document.getElementById('purifyChoiceRow').style.display='grid';
  document.getElementById('purifyOutcomeRow').style.display='none';
  document.getElementById('purifyOverlay').classList.add('show');
  update();
}

function choosePurification(boosted){
  purificationBoosted=boosted;

  if(boosted){
    if(!spendSparks(1)){
      document.getElementById('purifyResult').textContent=
        'Aucune Étincelle ne subsiste pour renforcer davantage la tentative.';
      return;
    }
    document.getElementById('purifyResult').textContent=
      'Vathkül renforce votre rituel. Effectuez un test d’Intelligence (Arcanes) ou de Sagesse (Religion), DD 15.';
  }else{
    document.getElementById('purifyResult').textContent=
      'Effectuez un test d’Intelligence (Arcanes) ou de Sagesse (Religion), DD 20.';
  }

  document.getElementById('purifyChoiceRow').style.display='none';
  document.getElementById('purifyOutcomeRow').style.display='grid';
  update();
}

function resolvePurification(success){
  if(pendingPurification===null)return;
  const i=pendingPurification;

  if(success){
    corrupted.delete(i);
lastGM=null;
    invalidateEvaluation();
    speakVathkul('La gravure retrouve sa pureté.');
  }else{
    spendSparks(1);
    speakVathkul('La souillure demeure.');
  }

  pendingPurification=null;
  purificationBoosted=false;
  document.getElementById('purifyOverlay').classList.remove('show');
  render();
}


function escapeHTML(value){
  return String(value).replaceAll('&','&amp;').replaceAll('<','&lt;').replaceAll('>','&gt;').replaceAll('"','&quot;').replaceAll("'",'&#039;');
}
function renderRitualJournal(){
  const container=document.getElementById('ritualJournal');
  if(!container)return;
  if(!ritualJournal.length){container.innerHTML='<div class="journal-empty">Aucun événement.</div>';return;}
  container.innerHTML=ritualJournal.slice().reverse().map(entry=>`
    <div class="journal-entry"><time>${new Date(entry.timestamp).toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'})}</time>
    <strong>${escapeHTML(entry.actor||'Le Monolithe')}</strong> — ${escapeHTML(entry.text)}</div>`).join('');
}
function addJournalEntry(text,actor=participantName||'Le Monolithe'){
  if(!text)return;
  ritualJournal.push({id:`${Date.now()}-${Math.random()}`,timestamp:Date.now(),actor,text});
  ritualJournal=ritualJournal.slice(-60);
  renderRitualJournal();
}
function initialSharedState(){
  return {
    schemaVersion:1,placements:Array(8).fill(null),order:[...schools],life:15,memoryLevel:Array(8).fill(0),
    corrupted:[],lastGM:null,evaluationVisible:false,ritualCompleted:false,
    pendingPurification:null,purificationBoosted:false,
    phaseHTML:'<b>Exploration :</b> placez librement les huit glyphes. Vathkül n’intervient pas tant que vous ne l’interrogez pas.',
    feedbackText:'Chaque épreuve, chaque souvenir et chaque tentative de purification consume au moins 1 Étincelle de Torm.',
    memoryText:'Sélectionnez une gravure du cercle, puis demandez à Vathkül d’éveiller un souvenir.',
    voiceText:'« Les Étincelles que Torm m’a confiées soutiennent encore mon serment. Employez-les avec discernement. »',
    memoryStage:'',memoryOverlayOpen:false,purifyOverlayOpen:false,
    purifyPrompt:'Vathkül engage une Étincelle de Torm pour retenir la corruption.',
    purifyResult:'Choisissez d’abord si Vathkül renforce votre tentative.',
    purifyChoiceVisible:true,purifyOutcomeVisible:false,boardDissolving:false,victoryOpen:false,
    ritualJournal:[{id:`reset-${Date.now()}`,timestamp:Date.now(),actor:'Le Monolithe',text:'Le rituel retrouve son état originel.'}]
  };
}
function resetRitualState(){
  spokenThresholds.clear();selected=null;previousLife=15;
  applySharedState(initialSharedState());
  document.getElementById('muralOverlay').classList.remove('show');
  document.getElementById('end').classList.remove('show');
  stateChangeHandler();
}


function setPurificationStep(step){
  const selectStep=document.getElementById('purificationSelectStep');
  const aidStep=document.getElementById('purificationAidStep');
  const rollStep=document.getElementById('purificationRollStep');

  selectStep?.classList.toggle('hidden',step!=='select');
  aidStep?.classList.toggle('hidden',step!=='aid');
  rollStep?.classList.toggle('hidden',step!=='roll');
}

function openPurificationFlow(){
  if(life<=0){
    speakVathkul('Aucune Étincelle ne demeure.');
    update();
    return;
  }

  purificationMode=true;
  purificationTargetIndex=null;
  purificationDC=20;

  document.querySelectorAll('.slot').forEach(slot=>{
    slot.classList.add('purification-selectable');
    slot.classList.remove('purification-target');
  });

  document.getElementById('purificationFlowOverlay')?.classList.remove('show');
  document.getElementById('purificationFlowOverlay')?.setAttribute('aria-hidden','true');

  addJournalEntry('Sélectionnez un glyphe à purifier.','Le Monolithe');
  speakVathkul('Sélectionnez un glyphe à purifier.');
  update();
}

function closePurificationFlow(){
  purificationMode=false;
  purificationTargetIndex=null;

  document.querySelectorAll('.slot').forEach(slot=>{
    slot.classList.remove('purification-selectable','purification-target');
  });

  document.getElementById('purificationFlowOverlay')?.classList.remove('show');
  document.getElementById('purificationFlowOverlay')?.setAttribute('aria-hidden','true');
}

function choosePurificationTarget(index){
  if(!purificationMode)return;

  if(!placements[index]){
    speakVathkul('Aucun glyphe ne repose à cet emplacement.');
    update();
    return;
  }

  purificationTargetIndex=index;

  document.querySelectorAll('.slot').forEach((slot,slotIndex)=>{
    slot.classList.toggle('purification-target',slotIndex===index);
  });

  speakVathkul('Désires-tu solliciter mon assistance ?');
  setPurificationStep('aid');

  const overlay=document.getElementById('purificationFlowOverlay');
  overlay?.classList.add('show');
  overlay?.setAttribute('aria-hidden','false');

  update();
}

function chooseVathkulAid(useAid){
  if(purificationTargetIndex===null)return;
  purificationDC=useAid?15:20;

  document.getElementById('purificationDcText').textContent=`DD ${purificationDC}`;
  document.getElementById('purificationRollInstruction').textContent=
    'Effectuez un jet d’Intelligence (Arcanes) ou de Sagesse (Religion).';

  addJournalEntry(
    useAid
      ? 'Vathkül prête son assistance à la purification. DD 15.'
      : 'La purification est tentée sans l’assistance de Vathkül. DD 20.'
  );

  setPurificationStep('roll');
}

function resolvePurification(success){
  if(purificationTargetIndex===null || life<=0)return;

  life=Math.max(0,life-1);

  if(success){
    const purifiedIndex=purificationTargetIndex;

    corrupted.delete(purifiedIndex);

    const purifiedSlot=document.querySelector(`.slot[data-index="${purifiedIndex}"]`);
    purifiedSlot?.classList.remove('corrupted');

    speakVathkul('Le glyphe retrouve sa pureté.');
    addJournalEntry('Le glyphe ciblé a été purifié.');

    closePurificationFlow();
    render();
    update();
    return;
  }else{
    speakVathkul('La souillure demeure.');
    addJournalEntry('La tentative de purification a échoué.');
  }

  previousLife=life;
  closePurificationFlow();
  update();
  stateChangeHandler();
}

function gmSwap(){
  const filled=[...Array(8).keys()].filter(i=>placements[i]);
  if(filled.length<2)return;
  const a=filled[Math.floor(Math.random()*filled.length)];
  let b=a;while(b===a)b=filled[Math.floor(Math.random()*filled.length)];
  [placements[a],placements[b]]=[placements[b],placements[a]];
  lastGM={type:'swap',a,b};invalidateEvaluation();say(`Deux gravures échangent brusquement leur fonction.`);render();
}

function gmCorrupt(){
  const filled=[...Array(8).keys()].filter(i=>placements[i]);
  if(!filled.length)return;
  const i=filled[Math.floor(Math.random()*filled.length)];
  corrupted.add(i);lastGM={type:'corrupt',i};invalidateEvaluation();say(`Une influence extérieure corrompt la gravure « ${stationNames[i]} ».`);render();
}
function gmRestore(){
  if(!lastGM)return;
  if(lastGM.type==='swap')[placements[lastGM.a],placements[lastGM.b]]=[placements[lastGM.b],placements[lastGM.a]];
  if(lastGM.type==='veil')
if(lastGM.type==='corrupt')corrupted.delete(lastGM.i);
  lastGM=null;invalidateEvaluation();say('La dernière perturbation est annulée.');render();
}
function say(t){
  document.getElementById('feedback').textContent=t;
  const last=ritualJournal.at(-1);
  if(!last||last.text!==t)addJournalEntry(t);
}


function exportSharedState(){
  return {
    schemaVersion:1,
    placements:[...placements],
    order:[...order],
    life,
    memoryLevel:[...memoryLevel],
    corrupted:[...corrupted],
    lastGM:lastGM ? {...lastGM} : null,
    evaluationVisible,
    ritualCompleted,
    pendingPurification,
    purificationBoosted,
    phaseHTML:document.getElementById('phase').innerHTML,
    feedbackText:document.getElementById('feedback').textContent,
    memoryText:document.getElementById('memoryText').textContent,
    voiceText:document.getElementById('vathkulVoice').textContent,
    memoryStage:document.getElementById('memoryStage').textContent,
    memoryOverlayOpen:document.getElementById('memoryOverlay').classList.contains('show'),
    purifyOverlayOpen:document.getElementById('purifyOverlay').classList.contains('show'),
    purifyPrompt:document.getElementById('purifyPrompt').textContent,
    purifyResult:document.getElementById('purifyResult').textContent,
    purifyChoiceVisible:document.getElementById('purifyChoiceRow').style.display!=='none',
    purifyOutcomeVisible:document.getElementById('purifyOutcomeRow').style.display!=='none',
    boardDissolving:document.getElementById('board').classList.contains('dissolving'),
    victoryOpen:document.getElementById('victory').classList.contains('show'),
    ritualJournal:ritualJournal.map(entry=>({...entry}))
  };
}

function applySharedState(sharedState){
  if(!sharedState || sharedState.schemaVersion!==1)return;

  isApplyingRemoteState=true;
  try{
    if(Array.isArray(sharedState.placements))placements=[...sharedState.placements];
    if(Array.isArray(sharedState.order))order=[...sharedState.order];
    if(Number.isFinite(sharedState.life))life=sharedState.life;
    if(Array.isArray(sharedState.memoryLevel))memoryLevel=[...sharedState.memoryLevel];

    corrupted=new Set(Array.isArray(sharedState.corrupted)?sharedState.corrupted:[]);
    lastGM=sharedState.lastGM ? {...sharedState.lastGM} : null;
    evaluationVisible=Boolean(sharedState.evaluationVisible);
    ritualCompleted=Boolean(sharedState.ritualCompleted);
    pendingPurification=Number.isInteger(sharedState.pendingPurification)
      ? sharedState.pendingPurification
      : null;
    purificationBoosted=Boolean(sharedState.purificationBoosted);
    ritualJournal=Array.isArray(sharedState.ritualJournal)?sharedState.ritualJournal.map(e=>({...e})).slice(-60):[];

    if(typeof sharedState.phaseHTML==='string'){
      document.getElementById('phase').innerHTML=sharedState.phaseHTML;
    }
    if(typeof sharedState.feedbackText==='string'){
      document.getElementById('feedback').textContent=sharedState.feedbackText;
    }
    if(typeof sharedState.memoryText==='string'){
      document.getElementById('memoryText').textContent=sharedState.memoryText;
    }
    if(typeof sharedState.voiceText==='string'){
      document.getElementById('vathkulVoice').textContent=sharedState.voiceText;
    }
    if(typeof sharedState.memoryStage==='string'){
      document.getElementById('memoryStage').textContent=sharedState.memoryStage;
    }
    if(typeof sharedState.purifyPrompt==='string'){
      document.getElementById('purifyPrompt').textContent=sharedState.purifyPrompt;
    }
    if(typeof sharedState.purifyResult==='string'){
      document.getElementById('purifyResult').textContent=sharedState.purifyResult;
    }

    document.getElementById('memoryOverlay').classList.toggle(
      'show',Boolean(sharedState.memoryOverlayOpen)
    );
    document.getElementById('purifyOverlay').classList.toggle(
      'show',Boolean(sharedState.purifyOverlayOpen)
    );
    document.getElementById('purifyChoiceRow').style.display=
      sharedState.purifyChoiceVisible ? 'grid' : 'none';
    document.getElementById('purifyOutcomeRow').style.display=
      sharedState.purifyOutcomeVisible ? 'grid' : 'none';
    document.getElementById('board').classList.toggle(
      'dissolving',Boolean(sharedState.boardDissolving)
    );
    document.getElementById('victory').classList.toggle(
      'show',Boolean(sharedState.victoryOpen)
    );

    previousLife=life;
    render();
    renderRitualJournal();

    const board=document.getElementById('board');
    board.classList.remove('remote-pulse');
    void board.offsetWidth;
    board.classList.add('remote-pulse');
  }finally{
    isApplyingRemoteState=false;
  }
}

window.ProjectMonolith={
  getParticipantName:()=>participantName,
  getSharedState:exportSharedState,
  applySharedState,
  onStateChange(handler){
    stateChangeHandler=typeof handler==='function' ? handler : ()=>{};
  },
  setSyncStatus(text,statusClass=''){
    const status=document.getElementById('syncStatus');
    if(!status)return;
    status.textContent=text;
    status.className='sync-chip'+(statusClass?' '+statusClass:'');
  },
  setPresence(names){
    const line=document.getElementById('presenceLine');
    if(!line)return;
    const unique=[...new Set((names||[]).filter(Boolean))];
    if(unique.length===0){
      line.textContent='Aucun autre esprit n’est encore lié au rituel.';
      return;
    }
    line.textContent='Volontés liées : '+unique.join(' · ');
  },
  resetRitual:resetRitualState,
  setSnapshotOptions(items){
    const select=document.getElementById('snapshotSelect'); if(!select)return;
    const current=select.value; select.innerHTML='';
    if(!items?.length){select.innerHTML='<option value="">Aucune sauvegarde disponible</option>';return;}
    items.forEach(item=>{const option=document.createElement('option');option.value=item.id;option.textContent=item.label;select.appendChild(option);});
    if([...select.options].some(o=>o.value===current))select.value=current;
  },
  setSnapshotStatus(text){const el=document.getElementById('snapshotStatus');if(el)el.textContent=text;}
};


document.getElementById('closePurificationFlow')?.addEventListener('click',closePurificationFlow);
document.getElementById('purificationAidYes')?.addEventListener('click',()=>chooseVathkulAid(true));
document.getElementById('purificationAidNo')?.addEventListener('click',()=>chooseVathkulAid(false));
document.getElementById('purificationSuccess')?.addEventListener('click',()=>resolvePurification(true));
document.getElementById('purificationFailure')?.addEventListener('click',()=>resolvePurification(false));
document.getElementById('purificationFlowOverlay')?.addEventListener('click',event=>{
  if(event.target.id==='purificationFlowOverlay')closePurificationFlow();
});

document.getElementById('lokaugSwap')?.addEventListener('click',startLokaugSwap);
document.getElementById('test').onclick=testConfiguration;
document.getElementById('memory').onclick=awakenMemory;
document.getElementById('beginPurify').onclick=openPurificationFlow;
document.getElementById('purifyNormal').onclick=()=>choosePurification(false);
document.getElementById('purifyBoost').onclick=()=>choosePurification(true);
document.getElementById('purifySuccess').onclick=()=>resolvePurification(true);
document.getElementById('purifyFailure').onclick=()=>resolvePurification(false);
document.getElementById('clear').onclick=()=>{placements.fill(null);invalidateEvaluation();render();say('Les huit glyphes retournent au bord du cercle.')};
document.getElementById('shuffle').onclick=()=>{order.sort(()=>Math.random()-.5);render()};
document.getElementById('memoryClose').onclick=()=>{
  document.getElementById('memoryOverlay').classList.remove('show');
  stateChangeHandler();
};
document.getElementById('openMural').onclick=inspectInnerEngravings;
document.getElementById('closeMural').onclick=()=>document.getElementById('muralOverlay').classList.remove('show');
document.getElementById('muralOverlay').onclick=e=>{if(e.target.id==='muralOverlay')document.getElementById('muralOverlay').classList.remove('show');};

document.getElementById('core').onclick=release;
document.getElementById('swap').onclick=gmSwap;
document.getElementById('corrupt').onclick=gmCorrupt;
document.getElementById('restore').onclick=gmRestore;

document.getElementById('resetRitual').onclick=()=>{
  if(confirm('Réinitialiser le rituel pour tous les participants ?')){
    window.ProjectMonolith.resetRitual();
    window.ProjectMonolith.setSnapshotStatus('Rituel réinitialisé.');
  }
};
document.getElementById('saveSnapshot').onclick=async()=>{
  const name=prompt('Nom de la sauvegarde :',`Sauvegarde ${new Date().toLocaleString('fr-FR')}`);
  if(name?.trim())await window.ProjectMonolithSync?.saveSnapshot(name.trim());
};
document.getElementById('loadSnapshot').onclick=async()=>{
  const id=document.getElementById('snapshotSelect').value;
  if(!id)return window.ProjectMonolith.setSnapshotStatus('Sélectionnez une sauvegarde.');
  if(confirm('Charger cette sauvegarde pour tous ?'))await window.ProjectMonolithSync?.loadSnapshot(id);
};
document.getElementById('deleteSnapshot').onclick=async()=>{
  const id=document.getElementById('snapshotSelect').value;
  if(!id)return window.ProjectMonolith.setSnapshotStatus('Sélectionnez une sauvegarde.');
  if(confirm('Supprimer cette sauvegarde ?'))await window.ProjectMonolithSync?.deleteSnapshot(id);
};

document.addEventListener('keydown',e=>{
  if(e.ctrlKey&&e.shiftKey&&e.key.toLowerCase()==='m'){
    e.preventDefault();document.getElementById('gmPanel').classList.toggle('show');
  }
});
